#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, M; scanf("%d %d", &N, &M);
        int *deg = (int*)calloc(N+1, sizeof(int));
        for(int i=0;i<M;i++){
            int a,b; scanf("%d %d", &a, &b);
            deg[a]++; deg[b]++;
        }
        long long inconvenience = 0;
        if(N==1){
            inconvenience = llabs(deg[1] - 0);
            printf("%lld 0\n", inconvenience);
        }else{
            // chain degrees
            inconvenience += llabs(deg[1] - 1);
            inconvenience += llabs(deg[N] - 1);
            for(int i=2;i<N;i++) inconvenience += llabs(deg[i] - 2);
            printf("%lld %d\n", inconvenience, N-1);
            for(int i=1;i<N;i++) printf("%d %d\n", i, i+1);
        }
        free(deg);
    }
    return 0;
}

