import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            long[] deg = new long[N+1];
            for (int i = 0; i < M; i++) {
                int a = fs.nextInt();
                int b = fs.nextInt();
                deg[a]++; deg[b]++;
            }
            long inc = 0;
            if (N == 1) {
                inc = Math.abs(deg[1]);
                out.append(inc).append(" 0\n");
            } else {
                inc += Math.abs(deg[1] - 1);
                inc += Math.abs(deg[N] - 1);
                for (int i = 2; i < N; i++) inc += Math.abs(deg[i] - 2);
                out.append(inc).append(' ').append(N-1).append('\n');
                for (int i = 1; i < N; i++) {
                    out.append(i).append(' ').append(i+1).append('\n');
                }
            }
        }
        System.out.print(out.toString());
    }
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign;
        }
    }
}

