#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        deg = [0]*(N+1)
        for __ in range(M):
            a = int(next(it)); b = int(next(it))
            deg[a] += 1
            deg[b] += 1
        if N == 1:
            inc = abs(deg[1])
            out_lines.append(f"{inc} 0")
        else:
            inc = abs(deg[1]-1) + abs(deg[N]-1)
            for i in range(2, N):
                inc += abs(deg[i]-2)
            out_lines.append(f"{inc} {N-1}")
            for i in range(1, N):
                out_lines.append(f"{i} {i+1}")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

